const messages = $json.messages || [];

return messages
  .map(m => {
    const msg = m.message;
    const level = msg.level || 0;
    const text = (msg.message || "").toLowerCase();

    let severity = null;

    // Existing severity logic
    if (level >= 4) {
      severity = 'CRITICAL';
    } else if (level === 3) {
      severity = 'WARNING';
    }

    // Authentication detection
    let authStatus = null;

    if (
      text.includes('failed password') ||
      text.includes('authentication failure') ||
      text.includes('invalid user') ||
      text.includes('login failed')
    ) {
      authStatus = 'AUTH_FAIL';
    } 
    else if (
      text.includes('accepted password') ||
      text.includes('login successful') ||
      text.includes('session opened') ||
      text.includes('authentication succeeded')
    ) {
      authStatus = 'AUTH_SUCCESS';
    }

    // Only pass CRITICAL, WARNING, or AUTH logs
    if (!severity && !authStatus) return null;

    return {
      json: {
        timestamp: msg.timestamp,
        host: msg.source || 'unknown',
        level,
        severity: severity || authStatus,
        auth_status: authStatus || null,
        message: msg.message
      }
    };
  })
  .filter(Boolean);

const grouped = {};

items.forEach(i => {
  const host = i.json.host;
  const severity = i.json.severity;
  const authStatus = i.json.auth_status || 'NONE';

  // Create grouping key including auth status
  const key = `${host}-${severity}-${authStatus}`;

  if (!grouped[key]) {
    grouped[key] = {
      host,
      severity,
      auth_status: authStatus !== 'NONE' ? authStatus : null,
      count: 0,
      messages: []
    };
  }

  grouped[key].count++;
  grouped[key].messages.push(i.json.message);
});

return Object.values(grouped).map(i => ({ json: i }));

let html = `<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; font-family:Arial; font-size:12px;">
<tr style="background:#f2f2f2">
<th>Host</th>
<th>Severity</th>
<th>Auth Status</th>
<th>Count</th>
<th>Sample Messages</th>
</tr>`;

items.forEach(i => {

  let color = 'black';

  if (i.json.severity === 'CRITICAL') {
    color = 'red';
  } else if (i.json.severity === 'WARNING') {
    color = 'orange';
  } else if (i.json.auth_status === 'AUTH_FAIL') {
    color = 'darkred';
  } else if (i.json.auth_status === 'AUTH_SUCCESS') {
    color = 'green';
  }

  html += `<tr>
<td>${i.json.host}</td>
<td style="color:${color}; font-weight:bold;">${i.json.severity}</td>
<td>${i.json.auth_status || '-'}</td>
<td>${i.json.count}</td>
<td style="max-width:500px; word-wrap:break-word;">
${i.json.messages.slice(0,5).join('<br>')}
</td>
</tr>`;
});

html += `</table>`;

return [{ json: { html } }];

